import{_ as e,c as a,o as l,V as t}from"./chunks/framework.9b555ede.js";const f=JSON.parse('{"title":"JS中的隐式转换","description":"","frontmatter":{},"headers":[],"relativePath":"note/JS中的隐式转换逻辑.md","filePath":"note/JS中的隐式转换逻辑.md","lastUpdated":1640693378000}'),i={name:"note/JS中的隐式转换逻辑.md"},o=t(`<h1 id="js中的隐式转换" tabindex="-1">JS中的隐式转换 <a class="header-anchor" href="#js中的隐式转换" aria-label="Permalink to &quot;JS中的隐式转换&quot;">​</a></h1><hr><h2 id="隐式转换触发时机" tabindex="-1">隐式转换触发时机 <a class="header-anchor" href="#隐式转换触发时机" aria-label="Permalink to &quot;隐式转换触发时机&quot;">​</a></h2><ul><li>不同类型比较时</li><li>使用运算符对非数字类型运算时</li><li>if的条件转换</li></ul><h2 id="比较时-遵守的规则如下" tabindex="-1">== 比较时，遵守的规则如下 <a class="header-anchor" href="#比较时-遵守的规则如下" aria-label="Permalink to &quot;== 比较时，遵守的规则如下&quot;">​</a></h2><ol><li>当同类型比较时，对象比较的是引用，原始值比较的就是值</li><li>当不同类型比较时，会转换为相同类型，然后再比较 <ul><li>Object会先尝试调用valueOf来获取一个原始类型，如果valueOf返回的不是原始类型，再尝试调用toString来得到一个原始类型，依然失败，就会报错。</li><li>string 转为 number</li><li>boolean 转为 number, true=1, false=0</li><li>null == undefined 只有它两相等，与其他值比较均为false</li><li>NaN 与任何值比较，都返回false，包括它自身 因此通过改写toString 或者valueOf方法，就能出现一些奇怪的现象</li></ul></li></ol><h2 id="当作为判定条件时-所有类型都会转为boolean类型" tabindex="-1">当作为判定条件时，所有类型都会转为Boolean类型 <a class="header-anchor" href="#当作为判定条件时-所有类型都会转为boolean类型" aria-label="Permalink to &quot;当作为判定条件时，所有类型都会转为Boolean类型&quot;">​</a></h2><ul><li>0,&#39;&#39;,null,undefined,NaN 为false，其他情况均为true</li></ul><h2 id="扩展下object-is-a-b" tabindex="-1">扩展下Object.is(a, b) <a class="header-anchor" href="#扩展下object-is-a-b" aria-label="Permalink to &quot;扩展下Object.is(a, b)&quot;">​</a></h2><pre><code>- Object.is(0, -0) // false
- Object.is(NaN, NaN) //true
- 其他情况与 === 相同，不会进行类型转换
</code></pre>`,10),n=[o];function r(s,c,d,_,u,h){return l(),a("div",null,n)}const m=e(i,[["render",r]]);export{f as __pageData,m as default};
